@namespace Lumeo

<div class="@CssClass" @attributes="AdditionalAttributes">
    @ChildContent
</div>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => $"flex gap-4 overflow-x-auto p-4 {Class}".Trim();
}

@namespace Lumeo

<div class="@CssClass"
     draggable="@(Draggable ? "true" : "false")"
     @onclick="OnClick"
     @attributes="AdditionalAttributes">

    @if (Labels is not null && Labels.Count > 0)
    {
        <div class="flex flex-wrap gap-1 mb-2">
            @foreach (var label in Labels)
            {
                <span class="@GetLabelClass(label.Color) inline-flex items-center px-1.5 py-0.5 rounded text-xs font-medium">
                    @label.Text
                </span>
            }
        </div>
    }

    @if (ChildContent is not null)
    {
        @ChildContent
    }
    else
    {
        <p class="text-sm font-medium leading-snug">@Title</p>
        @if (!string.IsNullOrEmpty(Description))
        {
            <p class="mt-1 text-xs text-muted-foreground line-clamp-2">@Description</p>
        }
    }

    @if (!string.IsNullOrEmpty(Avatar))
    {
        <div class="mt-2 flex justify-end">
            <img src="@Avatar" alt="Assignee" class="w-6 h-6 rounded-full object-cover border border-border/40" />
        </div>
    }
</div>

@code {
    [Parameter] public string? Title { get; set; }
    [Parameter] public string? Description { get; set; }
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public List<KanbanLabel>? Labels { get; set; }
    [Parameter] public string? Avatar { get; set; }
    [Parameter] public EventCallback OnClick { get; set; }
    [Parameter] public bool Draggable { get; set; } = true;
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => $"bg-card rounded-lg border border-border/40 p-3 shadow-sm cursor-pointer hover:shadow-md transition-shadow {Class}".Trim();

    private static string GetLabelClass(string color) => color switch
    {
        "primary" => "bg-primary/10 text-primary",
        "destructive" => "bg-destructive/10 text-destructive",
        "warning" => "bg-warning-light text-warning-text",
        "success" => "bg-success-light text-success-text",
        "secondary" => "bg-secondary text-secondary-foreground",
        _ => "bg-muted text-muted-foreground"
    };

    public class KanbanLabel
    {
        public string Text { get; set; } = "";
        public string Color { get; set; } = "primary";
    }
}

@namespace Lumeo

<div class="@CssClass" @attributes="AdditionalAttributes">
    <div class="flex items-center justify-between px-3 py-2 border-b border-border/40">
        @if (HeaderContent is not null)
        {
            @HeaderContent
        }
        else
        {
            <div class="flex items-center gap-2">
                <span class="font-medium text-sm">@Title</span>
                @if (Badge.HasValue)
                {
                    <span class="inline-flex items-center justify-center min-w-5 h-5 px-1.5 rounded-full bg-muted text-muted-foreground text-xs font-medium">
                        @Badge.Value
                    </span>
                }
            </div>
        }
    </div>

    <div class="flex-1 overflow-y-auto p-2 flex flex-col gap-2 min-h-16"
         @ondragover:preventDefault
         @ondrop="HandleDrop">
        @ChildContent
    </div>

    @if (AllowAdd)
    {
        <div class="p-2 border-t border-border/40">
            <button type="button"
                    class="w-full flex items-center gap-2 px-3 py-2 rounded-md text-sm text-muted-foreground hover:bg-muted/50 hover:text-foreground transition-colors"
                    @onclick="OnAdd">
                <Blazicon Svg="Lucide.Plus" class="h-3.5 w-3.5" />
                Add card
            </button>
        </div>
    }
</div>

@code {
    [Parameter] public string? Title { get; set; }
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public int? Badge { get; set; }
    [Parameter] public RenderFragment? HeaderContent { get; set; }
    [Parameter] public bool AllowAdd { get; set; }
    [Parameter] public EventCallback OnAdd { get; set; }
    [Parameter] public EventCallback<DragEventArgs> OnDrop { get; set; }

    private async Task HandleDrop(DragEventArgs e) => await OnDrop.InvokeAsync(e);
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => $"flex flex-col w-72 shrink-0 rounded-lg bg-muted/30 border border-border/40 max-h-full {Class}".Trim();
}
